messages.text:
Voy a pasarte el HTML de lo que me gustaría que fuese la nueva home. Adáptalo al estilo de la home actual

<!DOCTYPE html>
<html lang="es">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Paymático — Plataforma de Pagos Regulada</title>
<link href="https://fonts.googleapis.com/css2?family=DM+Sans:ital,opsz,wght@0,9..40,300;0,9..40,400;0,9..40,500;0,9..40,600;1,9..40,300&family=DM+Serif+Display:ital@0;1&display=swap" rel="stylesheet">
<style>
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

:root {
  --green: #A9E815;
  --green-dark: #7ab010;
  --navy: #0B132B;
  --navy-mid: #1a2340;
  --navy-soft: #252e4a;
  --gray: #829191;
  --white: #ffffff;
  --off: #F6F7F4;
  --off-2: #EDEEE9;
  --border: rgba(11,19,43,0.1);
  --border-strong: rgba(11,19,43,0.18);
  --text: #0B132B;
  --text-muted: #5a6472;
  --text-light: #8a909c;
  --radius: 14px;
  --radius-sm: 8px;
  --radius-xs: 6px;
}

html { scroll-behavior: smooth; }
body {
  font-family: 'DM Sans', sans-serif;
  color: var(--text);
  background: var(--white);
  font-size: 16px;
  line-height: 1.65;
  -webkit-font-smoothing: antialiased;
}

/* ─── NAV ─── */
nav {
  position: sticky; top: 0; z-index: 200;
  background: rgba(255,255,255,0.96);
  backdrop-filter: blur(10px);
  border-bottom: 1px solid var(--border);
  padding: 0 3rem;
  height: 64px;
  display: flex; align-items: center; justify-content: space-between;
}
.nav-logo {
  display: flex; align-items: center; gap: 10px;
  font-size: 20px; font-weight: 600; color: var(--navy); letter-spacing: -0.03em;
  text-decoration: none;
}
.logo-mark {
  width: 32px; height: 32px;
  background: var(--navy);
  border-radius: 8px;
  display: flex; align-items: center; justify-content: center;
  position: relative; overflow: hidden;
}
.logo-mark::after {
  content: '>';
  color: var(--green);
  font-size: 16px; font-weight: 700;
  line-height: 1;
}
.nav-links {
  display: flex; align-items: center; gap: 2rem;
  list-style: none;
}
.nav-links a {
  font-size: 14px; color: var(--text-muted); text-decoration: none; font-weight: 400;
  transition: color 0.2s;
}
.nav-links a:hover { color: var(--navy); }
.nav-right { display: flex; align-items: center; gap: 12px; }
.btn-ghost {
  font-size: 13px; font-weight: 500; color: var(--navy);
  background: none; border: 1px solid var(--border-strong);
  padding: 8px 16px; border-radius: var(--radius-sm); cursor: pointer;
  text-decoration: none; transition: background 0.2s;
}
.btn-ghost:hover { background: var(--off); }
.btn-primary {
  font-size: 13px; font-weight: 500; color: var(--navy);
  background: var(--green); border: none;
  padding: 9px 20px; border-radius: var(--radius-sm); cursor: pointer;
  text-decoration: none; transition: background 0.2s;
}
.btn-primary:hover { background: var(--green-dark); }

/* ─── HERO ─── */
.hero {
  background: var(--navy);
  padding: 100px 3rem 80px;
  position: relative; overflow: hidden;
}
.hero-grid-bg {
  position: absolute; inset: 0; opacity: 0.04;
  background-image:
    linear-gradient(rgba(169,232,21,1) 1px, transparent 1px),
    linear-gradient(90deg, rgba(169,232,21,1) 1px, transparent 1px);
  background-size: 48px 48px;
}
.hero-glow {
  position: absolute; top: -120px; right: -80px;
  width: 600px; height: 600px; border-radius: 50%;
  background: radial-gradient(circle, rgba(169,232,21,0.08) 0%, transparent 65%);
  pointer-events: none;
}
.hero-inner {
  position: relative; z-index: 1;
  max-width: 780px;
}
.hero-badge {
  display: inline-flex; align-items: center; gap: 8px;
  background: rgba(169,232,21,0.12);
  border: 1px solid rgba(169,232,21,0.25);
  border-radius: 100px;
  padding: 5px 14px 5px 10px;
  font-size: 12px; font-weight: 500; color: var(--green);
  margin-bottom: 2rem;
}
.hero-badge-dot {
  width: 6px; height: 6px; border-radius: 50%;
  background: var(--green);
}
.hero h1 {
  font-family: 'DM Serif Display', serif;
  font-size: clamp(2.4rem, 4.5vw, 3.5rem);
  line-height: 1.1;
  color: var(--white);
  letter-spacing: -0.02em;
  margin-bottom: 1.5rem;
  font-weight: 400;
}
.hero h1 em {
  font-style: italic;
  color: var(--green);
}
.hero-sub {
  font-size: 17px; font-weight: 300; color: rgba(255,255,255,0.68);
  line-height: 1.7; max-width: 580px;
  margin-bottom: 2.5rem;
}
.hero-sub strong { color: rgba(255,255,255,0.9); font-weight: 500; }
.hero-actions { display: flex; align-items: center; gap: 14px; flex-wrap: wrap; }
.hero-cta-main {
  display: inline-flex; align-items: center; gap: 8px;
  background: var(--green); color: var(--navy);
  font-size: 15px; font-weight: 600;
  padding: 14px 28px; border-radius: var(--radius-sm);
  text-decoration: none; border: none; cursor: pointer;
  transition: background 0.2s, transform 0.15s;
}
.hero-cta-main:hover { background: #bef530; transform: translateY(-1px); }
.hero-cta-sec {
  display: inline-flex; align-items: center; gap: 6px;
  color: rgba(255,255,255,0.6);
  font-size: 14px; font-weight: 400;
  text-decoration: none;
  transition: color 0.2s;
}
.hero-cta-sec:hover { color: rgba(255,255,255,0.9); }

/* ─── TRUST BAR ─── */
.trust-bar {
  background: var(--off);
  border-bottom: 1px solid var(--border);
  padding: 0 3rem;
}
.trust-bar-inner {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  divide-x: 1px solid var(--border);
}
.trust-item {
  padding: 1.5rem 1.75rem;
  border-right: 1px solid var(--border);
  display: flex; align-items: flex-start; gap: 12px;
}
.trust-item:last-child { border-right: none; }
.trust-icon {
  width: 36px; height: 36px; flex-shrink: 0;
  border-radius: var(--radius-sm);
  background: var(--navy);
  display: flex; align-items: center; justify-content: center;
  font-size: 16px;
}
.trust-item-text {}
.trust-item-title { font-size: 13px; font-weight: 600; color: var(--navy); line-height: 1.3; margin-bottom: 2px; }
.trust-item-desc { font-size: 12px; color: var(--text-muted); line-height: 1.45; }

/* ─── SECTION COMMON ─── */
section { padding: 90px 3rem; }
.section-label {
  display: inline-block;
  font-size: 11px; font-weight: 600; letter-spacing: 0.1em;
  text-transform: uppercase; color: var(--text-light);
  margin-bottom: 1rem;
}
.section-label-green { color: var(--green-dark); }
h2.section-title {
  font-family: 'DM Serif Display', serif;
  font-size: clamp(1.8rem, 3vw, 2.6rem);
  font-weight: 400; line-height: 1.15;
  letter-spacing: -0.02em;
  color: var(--navy);
  margin-bottom: 1rem;
}
h2.section-title em { font-style: italic; }
.section-intro {
  font-size: 17px; color: var(--text-muted);
  max-width: 560px; line-height: 1.7;
  margin-bottom: 3rem;
}

/* ─── VALUE PROPS ─── */
.value-section { background: var(--white); }
.value-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 1.5px;
  background: var(--border);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  overflow: hidden;
}
.value-card {
  background: var(--white);
  padding: 2rem 2rem 2.5rem;
  position: relative;
}
.value-card:hover { background: var(--off); }
.value-num {
  font-family: 'DM Serif Display', serif;
  font-size: 3rem; font-weight: 400;
  color: rgba(11,19,43,0.07);
  line-height: 1;
  position: absolute; top: 1.5rem; right: 1.75rem;
}
.value-card-icon {
  width: 44px; height: 44px;
  background: var(--navy);
  border-radius: var(--radius-sm);
  display: flex; align-items: center; justify-content: center;
  font-size: 20px;
  margin-bottom: 1.25rem;
}
.value-card h3 {
  font-size: 17px; font-weight: 600; color: var(--navy);
  margin-bottom: 0.5rem; line-height: 1.3;
}
.value-card p {
  font-size: 14px; color: var(--text-muted); line-height: 1.6;
}

/* ─── SEGMENTS ─── */
.segments-section { background: var(--off); }
.segments-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 1.5rem; }
.seg-card {
  background: var(--white);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  overflow: hidden;
  transition: box-shadow 0.2s, transform 0.2s;
}
.seg-card:hover { box-shadow: 0 8px 32px rgba(11,19,43,0.08); transform: translateY(-2px); }
.seg-card-header {
  padding: 2rem 2rem 1.5rem;
  border-bottom: 1px solid var(--border);
}
.seg-tag {
  display: inline-block;
  font-size: 11px; font-weight: 600; letter-spacing: 0.06em;
  text-transform: uppercase;
  padding: 4px 10px; border-radius: 100px;
  margin-bottom: 1rem;
}
.seg-tag-navy { background: rgba(11,19,43,0.07); color: var(--navy); }
.seg-tag-green { background: rgba(169,232,21,0.2); color: var(--green-dark); }
.seg-card-header h3 {
  font-family: 'DM Serif Display', serif;
  font-size: 1.4rem; font-weight: 400;
  color: var(--navy); line-height: 1.2;
  margin-bottom: 0.75rem;
}
.seg-card-header p {
  font-size: 14px; color: var(--text-muted); line-height: 1.6;
}
.seg-subverticals {
  padding: 1.25rem 2rem;
}
.seg-subverticals-label {
  font-size: 11px; font-weight: 600; letter-spacing: 0.07em;
  text-transform: uppercase; color: var(--text-light);
  margin-bottom: 0.75rem;
}
.sub-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 8px; margin-bottom: 1.25rem; }
.sub-chip {
  display: flex; align-items: center; justify-content: space-between;
  padding: 9px 12px;
  background: var(--off);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  font-size: 13px; font-weight: 500; color: var(--navy);
  text-decoration: none; cursor: pointer;
  transition: background 0.15s, border-color 0.15s;
}
.sub-chip:hover {
  background: var(--navy); color: var(--white);
  border-color: var(--navy);
}
.sub-chip-arrow { font-size: 11px; opacity: 0.5; }
.sub-chip:hover .sub-chip-arrow { opacity: 1; }
.seg-cta {
  display: inline-flex; align-items: center; gap: 6px;
  font-size: 13px; font-weight: 600; color: var(--navy);
  text-decoration: none;
  padding-top: 0.25rem;
  border-bottom: 1.5px solid var(--navy);
  transition: opacity 0.2s;
}
.seg-cta:hover { opacity: 0.6; }

.seg-card-isv .seg-card-header { border-bottom: none; padding-bottom: 0; }
.seg-card-isv { display: flex; flex-direction: column; }
.isv-body { padding: 1.5rem 2rem 2rem; flex: 1; display: flex; flex-direction: column; justify-content: space-between; }
.isv-features { display: flex; flex-direction: column; gap: 10px; margin-bottom: 1.5rem; }
.isv-feat {
  display: flex; align-items: flex-start; gap: 10px;
  font-size: 13px; color: var(--text-muted);
}
.isv-feat-dot {
  width: 6px; height: 6px; border-radius: 50%;
  background: var(--green);
  margin-top: 7px; flex-shrink: 0;
}

/* ─── HOW IT WORKS ─── */
.how-section { background: var(--white); }
.steps { display: grid; grid-template-columns: repeat(3, 1fr); gap: 0; position: relative; }
.steps::before {
  content: '';
  position: absolute; top: 28px; left: calc(16.666% + 28px); right: calc(16.666% + 28px);
  height: 1px; background: var(--border);
  z-index: 0;
}
.step { padding: 0 2rem; text-align: left; position: relative; }
.step-num {
  width: 56px; height: 56px;
  border-radius: 50%;
  border: 1px solid var(--border);
  background: var(--white);
  display: flex; align-items: center; justify-content: center;
  font-family: 'DM Serif Display', serif;
  font-size: 1.4rem; font-weight: 400; color: var(--navy);
  margin-bottom: 1.5rem;
  position: relative; z-index: 1;
}
.step h3 { font-size: 16px; font-weight: 600; color: var(--navy); margin-bottom: 0.5rem; }
.step p { font-size: 14px; color: var(--text-muted); line-height: 1.6; }

/* ─── SUPPORT ─── */
.support-section {
  background: var(--navy);
  position: relative; overflow: hidden;
}
.support-glow {
  position: absolute; bottom: -100px; left: -100px;
  width: 500px; height: 500px; border-radius: 50%;
  background: radial-gradient(circle, rgba(169,232,21,0.06) 0%, transparent 65%);
  pointer-events: none;
}
.support-inner {
  position: relative; z-index: 1;
  display: grid; grid-template-columns: 1fr 1fr; gap: 5rem; align-items: center;
}
.support-left h2 {
  font-family: 'DM Serif Display', serif;
  font-size: clamp(1.8rem, 2.8vw, 2.4rem);
  font-weight: 400; line-height: 1.2;
  color: var(--white); letter-spacing: -0.02em;
  margin-bottom: 1.25rem;
}
.support-left h2 em { font-style: italic; color: var(--green); }
.support-left p { font-size: 16px; color: rgba(255,255,255,0.6); line-height: 1.7; font-weight: 300; }
.support-cards { display: flex; flex-direction: column; gap: 12px; }
.support-card {
  background: rgba(255,255,255,0.05);
  border: 1px solid rgba(255,255,255,0.1);
  border-radius: var(--radius);
  padding: 1.25rem 1.5rem;
  display: flex; gap: 14px; align-items: flex-start;
}
.support-card-icon {
  width: 36px; height: 36px; flex-shrink: 0;
  background: rgba(169,232,21,0.15);
  border-radius: var(--radius-sm);
  display: flex; align-items: center; justify-content: center;
  font-size: 16px;
}
.support-card h4 { font-size: 14px; font-weight: 600; color: var(--white); margin-bottom: 2px; }
.support-card p { font-size: 13px; color: rgba(255,255,255,0.5); line-height: 1.5; }

/* ─── CTA FINAL ─── */
.cta-section {
  background: var(--off);
  text-align: center;
  padding: 100px 3rem;
}
.cta-section h2 {
  font-family: 'DM Serif Display', serif;
  font-size: clamp(2rem, 3.5vw, 3rem);
  font-weight: 400; line-height: 1.15;
  color: var(--navy); letter-spacing: -0.02em;
  margin-bottom: 1rem;
}
.cta-section h2 em { font-style: italic; }
.cta-section p { font-size: 17px; color: var(--text-muted); margin-bottom: 2.5rem; max-width: 480px; margin-left: auto; margin-right: auto; }
.cta-actions { display: flex; align-items: center; justify-content: center; gap: 14px; }
.cta-main {
  display: inline-flex; align-items: center; gap: 8px;
  background: var(--navy); color: var(--white);
  font-size: 15px; font-weight: 600;
  padding: 15px 32px; border-radius: var(--radius-sm);
  text-decoration: none; transition: opacity 0.2s;
}
.cta-main:hover { opacity: 0.85; }
.cta-phone {
  font-size: 14px; color: var(--text-muted);
}
.cta-phone a { color: var(--navy); font-weight: 500; text-decoration: none; }

/* ─── FOOTER ─── */
footer {
  background: var(--navy);
  padding: 3rem 3rem 2rem;
  color: rgba(255,255,255,0.5);
  font-size: 13px;
}
.footer-top {
  display: grid; grid-template-columns: 2fr 1fr 1fr 1fr;
  gap: 3rem; margin-bottom: 3rem;
  padding-bottom: 2.5rem;
  border-bottom: 1px solid rgba(255,255,255,0.08);
}
.footer-brand p { font-size: 13px; color: rgba(255,255,255,0.4); margin-top: 0.75rem; line-height: 1.6; max-width: 240px; }
.footer-col h4 { font-size: 12px; font-weight: 600; color: rgba(255,255,255,0.7); letter-spacing: 0.06em; text-transform: uppercase; margin-bottom: 1rem; }
.footer-col a {
  display: block; color: rgba(255,255,255,0.4);
  text-decoration: none; margin-bottom: 0.5rem; font-size: 13px;
  transition: color 0.2s;
}
.footer-col a:hover { color: rgba(255,255,255,0.8); }
.footer-bottom {
  display: flex; align-items: center; justify-content: space-between;
}
.footer-legal { font-size: 12px; color: rgba(255,255,255,0.3); line-height: 1.5; max-width: 600px; }
.footer-seals { display: flex; gap: 8px; }
.seal {
  border: 1px solid rgba(255,255,255,0.15);
  border-radius: var(--radius-xs);
  padding: 4px 10px;
  font-size: 10px; font-weight: 600; letter-spacing: 0.05em;
  color: rgba(255,255,255,0.4); text-transform: uppercase;
}

/* ─── LOGOS ─── */
.logos-section {
  background: var(--white);
  padding: 56px 3rem;
  border-top: 1px solid var(--border);
  border-bottom: 1px solid var(--border);
}
.logos-label {
  font-size: 12px; font-weight: 600; letter-spacing: 0.1em;
  text-transform: uppercase; color: var(--text-light);
  text-align: center; margin-bottom: 2rem;
}
.logos-row {
  display: flex; align-items: center; justify-content: center;
  gap: 5rem; flex-wrap: wrap;
}
.logo-item {
  display: flex; flex-direction: column; align-items: center; gap: 5px;
  opacity: 0.5; transition: opacity 0.2s;
}
.logo-item:hover { opacity: 1; }
.logo-wordmark {
  font-family: 'DM Serif Display', serif;
  font-size: 1.5rem; font-weight: 400;
  color: var(--navy); letter-spacing: -0.02em;
  line-height: 1;
}
.logo-wordmark span { color: var(--green-dark); }
.logo-sector { font-size: 11px; color: var(--text-light); letter-spacing: 0.04em; }

/* ─── TESTIMONIALS ─── */
.testimonials-section {
  background: var(--navy);
  padding: 90px 3rem;
  position: relative; overflow: hidden;
}
.testimonials-section .section-label { color: rgba(169,232,21,0.7); }
.testimonials-section h2.section-title { color: var(--white); margin-bottom: 3rem; }
.slider-wrap { position: relative; overflow: hidden; }
.slider-track {
  display: flex;
  transition: transform 0.45s cubic-bezier(0.4,0,0.2,1);
}
.testimonial-card {
  min-width: 100%; width: 100%;
  background: rgba(255,255,255,0.05);
  border: 1px solid rgba(255,255,255,0.1);
  border-radius: var(--radius);
  padding: 2.5rem 2.5rem 2rem;
  position: relative;
}
.quote-mark {
  font-family: 'DM Serif Display', serif;
  font-size: 5rem; line-height: 0.7;
  color: rgba(169,232,21,0.15);
  position: absolute; top: 1.5rem; left: 2rem;
  pointer-events: none; user-select: none;
}
.testimonial-text {
  font-family: 'DM Serif Display', serif;
  font-size: clamp(1.05rem, 1.5vw, 1.2rem);
  font-style: italic;
  color: rgba(255,255,255,0.88);
  line-height: 1.7;
  margin-bottom: 2rem;
  padding-top: 1.25rem;
}
.testimonial-author { display: flex; align-items: center; gap: 14px; }
.author-avatar {
  width: 48px; height: 48px; border-radius: 50%;
  background: var(--navy-soft);
  border: 2px solid rgba(169,232,21,0.3);
  display: flex; align-items: center; justify-content: center;
  font-family: 'DM Serif Display', serif;
  font-size: 1.1rem; color: var(--green);
  flex-shrink: 0; overflow: hidden;
}
.author-name { font-size: 14px; font-weight: 600; color: var(--green); margin-bottom: 2px; }
.author-role { font-size: 13px; color: rgba(255,255,255,0.45); }
.slider-controls { display: flex; align-items: center; gap: 12px; margin-top: 2rem; }
.slider-btn {
  width: 40px; height: 40px; border-radius: 50%;
  border: 1px solid rgba(255,255,255,0.2);
  background: rgba(255,255,255,0.06);
  color: rgba(255,255,255,0.7);
  font-size: 16px; cursor: pointer;
  display: flex; align-items: center; justify-content: center;
  transition: background 0.2s, border-color 0.2s, color 0.2s;
}
.slider-btn:hover { background: rgba(169,232,21,0.15); border-color: rgba(169,232,21,0.4); color: var(--green); }
.slider-dots { display: flex; gap: 6px; align-items: center; }
.slider-dot {
  width: 6px; height: 6px; border-radius: 50%;
  background: rgba(255,255,255,0.25); cursor: pointer;
  transition: background 0.2s, transform 0.2s;
  border: none;
}
.slider-dot.active { background: var(--green); transform: scale(1.4); }

/* ─── ANIMATIONS ─── */
@keyframes fadeUp {
  from { opacity: 0; transform: translateY(20px); }
  to { opacity: 1; transform: translateY(0); }
}
.hero-badge { animation: fadeUp 0.5s ease both; }
.hero h1 { animation: fadeUp 0.5s 0.1s ease both; }
.hero-sub { animation: fadeUp 0.5s 0.2s ease both; }
.hero-actions { animation: fadeUp 0.5s 0.3s ease both; }
</style>
</head>
<body>

<!-- NAV -->
<nav>
  <a href="#" class="nav-logo">
    <div class="logo-mark"></div>
    paymático
  </a>
  <ul class="nav-links">
